{action_set_definitions}: {
  "get_student_status": {
    "description": "Retrieves the current state of a student, including knowledge levels, engagement, fatigue, and session time.",
    "parameters": {
      "type": "object",
      "properties": {
        "student_name": {
          "type": "string",
          "description": "The name of the student to query."
        }
      },
      "required": [
        "student_name"
      ]
    },
    "example_output": {
      "knowledge_profile": {
        "topic_id_1": 0.65
      },
      "engagement_level": 0.8,
      "fatigue_level": 0.2,
      "session_duration_mins": 10
    }
  },
  "identify_prerequisite_deficit": {
    "description": "Analyzes a knowledge profile to find the specific topic that serves as the primary foundational deficit for a target module.",
    "parameters": {
      "type": "object",
      "properties": {
        "target_module": {
          "type": "string",
          "description": "The module the student aims to unlock."
        },
        "knowledge_profile": {
          "type": "object",
          "description": "The current mapping of topic masteries."
        }
      },
      "required": [
        "target_module",
        "knowledge_profile"
      ]
    },
    "example_output": {
      "deficit_topic_id": "MATH_DE_BASE",
      "current_mastery": 0.72
    }
  },
  "execute_learning_activity": {
    "description": "Performs an instructional intervention. Increases mastery, fatigue, and session duration. Intensity affects the rate of these changes.",
    "parameters": {
      "type": "object",
      "properties": {
        "topic_id": {
          "type": "string",
          "description": "The ID of the topic to teach."
        },
        "intensity": {
          "type": "string",
          "enum": [
            "low",
            "medium",
            "high"
          ],
          "description": "Low: minimal fatigue, slow mastery gain. Medium: balanced. High: high fatigue, fast mastery gain."
        }
      },
      "required": [
        "topic_id",
        "intensity"
      ]
    },
    "example_output": {
      "new_mastery": 0.78,
      "fatigue_increase": 0.05,
      "duration_increase": 7
    }
  },
  "administer_competency_test": {
    "description": "Runs an adaptive diagnostic test. Takes exactly 8 minutes. Returns competency estimate and Standard Error of Measurement (SEM).",
    "parameters": {
      "type": "object",
      "properties": {
        "module_id": {
          "type": "string",
          "description": "The module to test."
        }
      },
      "required": [
        "module_id"
      ]
    },
    "example_output": {
      "competency_estimate": 0.82,
      "sem": 0.28,
      "fatigue_increase": 0.1,
      "duration_increase": 8
    }
  },
  "apply_engagement_intervention": {
    "description": "Uses a motivational technique to restore student focus.",
    "parameters": {
      "type": "object",
      "properties": {
        "student_name": {
          "type": "string"
        }
      },
      "required": [
        "student_name"
      ]
    },
    "example_output": {
      "new_engagement": 0.9,
      "duration_increase": 2
    }
  }
}
